import { useEffect, useState } from 'react';
import { useLocation } from 'react-router-dom';
import { fetchDestinations } from '../services/api';
import DestinationCard from '../components/DestinationCards';
import CreateDestination from '../components/DestinationsCreate';
import { GoogleMap, LoadScript, Marker, Autocomplete } from '@react-google-maps/api';
import '../styles/GroupDetails.css';
import '../styles/Groups.css';

export default function Destinations() {
    const { state } = useLocation();
    const [groups, setDestinations] = useState([]);
    const [showModal, setShowModal] = useState(false);

    const groupMembers = state?.members || [];
    const groupName = state?.groupName || "Nos destinations";

    useEffect(() => {
        fetchDestinations().then(setDestinations);
    }, []);

    return (
        <div className="groups-container">
            <div className="groups-header">
                <h1 className="groups-title">{groupName}</h1>

                {groupMembers.length > 0 && (
                    <p className="group-members">
                        Membres : {groupMembers.join(', ')}
                    </p>
                )}

                <button
                    className="create-group-button"
                    onClick={() => setShowModal(true)}
                >
                    Créer une destination
                </button>
            </div>
            <div className="group-banner">
                <LoadScript googleMapsApiKey="AIzaSyCYi43JdVAzPYWGqsNP724LNeA2MQK7z8w" libraries={['places']}>
                    
                    <Autocomplete
                        onLoad={(autocomplete) => (autocompleteRef.current = autocomplete)}
                        onPlaceChanged={handlePlaceChanged}
                    >
                        <input
                            type="text"
                            placeholder="Rechercher une adresse..."
                            style={{
                                width: '100%',
                                padding: '10px',
                                fontSize: '16px',
                                borderRadius: '8px',
                                marginBottom: '10px',
                                border: '1px solid #ccc',
                            }}
                        />
                    </Autocomplete>

                    <GoogleMap
                        mapContainerStyle={mapContainerStyle}
                        center={mapCenter}
                        zoom={12}
                    >
                        {markerPosition && <Marker position={markerPosition} />}
                    </GoogleMap>
                </LoadScript>
            </div>
            <div className="groups-grid">
                {groups.map(group => (
                    <DestinationCard
                    key={group.id}
                    id={group.id}
                    name={group.name}
                    image={group.image}
                    price={group.price}
                    startDate={group.startDate}
                    endDate={group.endDate}
                    creator={group.creator}
                    comments={group.comments}
                />
                
                ))}
            </div>

                        {showModal && (
                <div className="modal-overlay">
                    <div className="modal-content">
                        <button className="close-modal" onClick={() => setShowModal(false)}>✖</button>
                        <CreateDestination
                            onClose={() => setShowModal(false)}
                            onCreate={(newGroup) => setDestinations(prev => [...prev, newGroup])}
                        />
                    </div>
                </div>
            )}

        </div>
    );
}
